    "subtitlePekingDuck": "\u5317\u4eac\u4f20\u5947\u70e4\u9e2d",
    "contentPekingDuck": "<p>\u5317\u4eac\u70e4\u9e2d\u662f\u6765\u81ea\u5317\u4eac\u7684\u83dc\u80b4\uff0c\u53ef\u8ffd\u6eaf\u81f3\u7687\u5ba4\u65f6\u4ee3\u3002\u8089\u7684\u7279\u70b9\u662f\u8584\u800c\u8106\u7684\u76ae\uff0c\u6b63\u5b97\u7684\u7248\u672c\u5728\u98df\u5ba2\u9762\u524d\u7531\u53a8\u5e08\u5207\u7247\uff0c\u901a\u5e38\u4e3b\u8981\u63d0\u4f9b\u76ae\u548c\u5c11\u91cf\u8089\u3002</p><p>\u9e2d\u5b50\u662f\u4e13\u95e8\u4e3a\u8fd9\u9053\u83dc\u9972\u517b\u7684\uff0c\u572865\u5929\u540e\u5bb0\u6740\u5e76\u8c03\u5473\uff0c\u7136\u540e\u5728\u5c01\u95ed\u6216\u60ac\u6302\u7089\u4e2d\u70e4\u5236\u3002\u8089\u901a\u5e38\u4e0e\u5927\u8471\u3001\u9ec4\u74dc\u548c\u751c\u9762\u9171\u4e00\u8d77\u98df\u7528\uff0c\u7528\u8584\u997c\u5377\u7740\u9985\u6599\u4e00\u8d77\u5403\u3002</p>",
    "recipeIngredientPekingDuck": "1 whole duck (specially bred for Peking Duck), 2 stalks scallion, 1 cucumber, 3 tbsp sweet bean sauce, 8 thin pancakes",
    "recipeInstructionsPekingDuck": [
      "Prepare the duck: breed for 65 days, slaughter and season before roasting.",
      "Roast the duck in a closed or hung oven until the skin is thin and crisp.",
      "Slice the duck tableside \u2014 the cook presents mostly skin and little meat.",
      "Serve with spring onion, cucumber strips, and sweet bean sauce, rolled in thin pancakes."
    ],
    "titleDimSum": "\u70b9\u5fc3",
    "subtitleDimSum": "\u6765\u81ea\u5e7f\u4e1c\u7684\u5320\u5fc3\u4e4b\u4f5c",
    "contentDimSum": "<p>\u70b9\u5fc3\u662f\u4e2d\u56fd\u5404\u79cd\u5c0f\u83dc\u7684\u7edf\u79f0\uff0c\u4f20\u7edf\u4e0a\u5728\u9910\u5385\u4eab\u7528\u65e9\u5348\u9910\u3002\u5927\u591a\u6570\u73b0\u4ee3\u70b9\u5fc3\u83dc\u6e90\u4e8e\u4e2d\u56fd\uff0c\u901a\u5e38\u4e0e\u7ca4\u83dc\u76f8\u5173\u3002</p><p>\u83dc\u80b4\u901a\u5e38\u914d\u8336\u4e00\u8d77\u98df\u7528\uff0c\u5f62\u6210\u5b8c\u6574\u7684\u8336\u70b9\u65e9\u5348\u9910\u3002\u70b9\u5fc3\u83dc\u901a\u5e38\u4ee5\u5c0f\u84b8\u7b3c\u6216\u5c0f\u76d8\u5b50\u4f9b\u5e94\u7684\u5c0f\u53e3\u98df\u7269\u5f62\u5f0f\u51c6\u5907\u3002</p>",
    "recipeIngredientDimSum": "200g rice flour, 100g wheat starch, 200g ground pork, 100g shrimp, 1 tbsp sesame oil, 1 tsp soy sauce, assorted vegetables, bamboo steamer baskets",
    "recipeInstructionsDimSum": [
      "Make the dough: mix rice flour and wheat starch with hot water, knead until smooth.",
      "Prepare fillings: combine ground pork, shrimp, sesame oil, and soy sauce with finely chopped vegetables.",
      "Roll dough into small thin circles, place a spoonful of filling in the center.",
      "Fold and pinch the edges to seal, then steam in bamboo baskets for 8\u201310 minutes.",
      "Serve hot with Chinese tea as part of a dim sum brunch."
    ],
    "titleHotpot": "\u706b\u9505",
    "subtitleHotpot": "\u6700\u4f73\u793e\u4ea4\u9910\u996e",
    "contentHotpot": "<p>\u706b\u9505\uff0c\u53c8\u79f0\u706b\u9505\uff0c\u662f\u4e00\u79cd\u6e90\u81ea\u4e2d\u56fd\u7684\u70f9\u996a\u65b9\u6cd5\uff0c\u5728\u9910\u684c\u4e0a\u63d0\u4f9b\u4e00\u4e2a\u6b63\u5728\u6cb8\u817e\u7684\u6c64\u9505\uff0c\u91cc\u9762\u6709\u5404\u79cd\u4e1c\u4e9a\u98df\u6750\u548c\u914d\u6599\u3002</p><p>\u5178\u578b\u914d\u6599\u5305\u62ec\u8584\u8089\u7247\u3001\u53f6\u83dc\u3001\u8611\u83c7\u3001\u9984\u9968\u3001\u86cb\u997a\u5b50\u3001\u8c46\u8150\u548c\u6d77\u9c9c\u3002\u719f\u98df\u901a\u5e38\u914d\u8638\u9171\u4e00\u8d77\u98df\u7528\u3002</p>",
    "recipeIngredientHotpot": "300g thinly sliced lamb or beef, 200g leaf vegetables, 100g mushrooms, 8 won tons, 150g tofu, 100g seafood, 1L hot soup stock, dipping sauce",
    "recipeInstructionsHotpot": [
      "\u5c06\u6c64\u6599\u653e\u5728\u9910\u684c\u4e0a\u7684\u706b\u9505\u5bb9\u5668\u4e2d\u716e\u6cb8\u3002",
      "\u51c6\u5907\u6750\u6599\uff1a\u8089\u5207\u8584\u7247\uff0c\u852c\u83dc\u6d17\u51c0\uff0c\u8c46\u8150\u5207\u7247\uff0c\u6d77\u9c9c\u6d17\u51c0\u3002",
      "\u7528\u7b77\u5b50\u6216\u52fa\u5b50\u5c06\u914d\u6599\u6dfb\u52a0\u5230\u716e\u6cb8\u7684\u8089\u6c64\u4e2d\u3002",
      "\u716e\u81f3\u8089\u548c\u852c\u83dc\u719f\u900f\u2014\u2014\u65f6\u95f4\u56e0\u539f\u6599\u800c\u5f02\u3002",
      "\u5c06\u716e\u719f\u7684\u98df\u6750\u6d78\u5165\u60a8\u9009\u62e9\u7684\u8638\u9171\u4e2d\u5e76\u4eab\u7528\u3002"
    ],
    "titleDumplings": "\u997a\u5b50\uff08Jiaozi\uff09",
    "subtitleDumplings": "\u4f20\u7edf\u4e0e\u7e41\u8363\u7684\u5473\u9053",
    "contentDumplings": "<p>\u997a\u5b50\u662f\u4e2d\u56fd\u997a\u5b50\u7684\u4e00\u79cd\uff0c\u5728\u4e2d\u56fd\u548c\u5176\u4ed6\u4e1c\u4e9a\u5730\u533a\u666e\u904d\u98df\u7528\u3002\u5b83\u4eec\u662f\u4e2d\u56fd\u65b0\u5e74\u671f\u95f4\u53ca\u5317\u65b9\u5404\u7701\u5168\u5e74\u98df\u7528\u7684\u4e3b\u8981\u98df\u7269\u4e4b\u4e00\u3002</p><p>\u5b83\u4eec\u7531\u8089\u9985\u548c/\u6216\u852c\u83dc\u9985\u5305\u88f9\u5728\u8584\u64c0\u7684\u9762\u56e2\u4e2d\uff0c\u7136\u540e\u901a\u8fc7\u6309\u538b\u8fb9\u7f18\u5bc6\u5c01\u800c\u6210\u3002</p>",
    "recipeIngredientDumplings": "250g ground pork or beef, 1 cup Napa cabbage (shredded and salted), 2 tbsp soy sauce, 1 tbsp sesame oil, 1 package dumpling wrappers, 1 egg white (sealing)",
    "recipeInstructionsDumplings": [
      "Make the filling: combine ground meat, drained cabbage, soy sauce, and sesame oil.",
      "Place a spoonful of filling in the center of each dumpling wrapper.",
      "Brush edges with egg white and fold the wrapper, pressing edges to seal.",
      "Boil, steam, or pan-fry the dumplings until fully cooked.",
      "Serve during Chinese New Year or year-round with dipping sauce of black vinegar and ginger."
    ],
