    "footerDisclaimer": "\uc774\uac83\uc740 \ud504\ub808\uc820\ud14c\uc774\uc158 \uc6f9\uc0ac\uc774\ud2b8\uc785\ub2c8\ub2e4. \ubaa8\ub4e0 \uc774\ubbf8\uc9c0\ub294 \uc124\uba85 \ubaa9\uc801\uc73c\ub85c Unsplash\uc5d0\uc11c \uac00\uc838\uc628 \uac83\uc785\ub2c8\ub2e4.",
