    "visaPageTitle": "\ucc28\uc774\ub098 \ud22c\uc5b4 \u2014 \ubb38\ud654, \ud48d\uacbd, \uc694\ub9ac",
    "visaPaymentDesc": "\uc911\uad6d\uc5d0\uc11c\ub294 Alipay\uc640 WeChat Pay \uac19\uc740 \ubaa8\ubc14\uc77c \uacb0\uc81c\uac00 \uc8fc\ub958\uc785\ub2c8\ub2e4. \ud638\ud154\uacfc \ub300\uaddc\ubaa8 \ub9e4\uc7a5\uc5d0\uc11c\ub294 \uc8fc\uc694 \uc2e0\uc6a9\uce74\ub4dc\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
