    "visaTip1Title": "\ucd9c\ubc1c \uc804 \ud655\uc778",
    "visaTip2Desc": "\ub9ce\uc740 \uad6d\uac00\uc758 \uad6d\ubbfc\uc740 24~144\uc2dc\uac04 \uc774\ub0b4\uc5d0 \uc911\uad6d \uacf5\ud56d\uc744 \uacbd\uc720\ud558\uace0 \uacf5\ud56d \uad6c\uc5ed\uc744 \ubc97\uc5b4\ub098\uc9c0 \uc54a\uc73c\uba74 \ube44\uc790 \uc5c6\uc774 \uc804\ud658\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uad6c\uccb4\uc801\uc778 \uc804\ud658 \uc870\uac74\uc744 \ud655\uc778\ud558\uc138\uc694.",
    "visaTip2Title": "\uacbd\uc720 \uba74\uc81c",
    "visaTip3Desc": "\ud64d\ucf69\uacfc \ub9c8\uce74\uc624\ub294 \ubcc4\ub3c4\uc758 \ucd9c\uc785\uad6d \uaddc\uc81c\uac00 \uc788\uc2b5\ub2c8\ub2e4. \ub9ce\uc740 \uad6d\uc801\uc740 \ub2e8\uae30 \uccb4\ub958\ub85c \uc774\ub7ec\ud55c \uc9c0\uc5ed\uc744 \ube44\uc790 \uc5c6\uc774 \ubc29\ubb38\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4. SAR\ubcc4 \uc694\uad6c \uc0ac\ud56d\uc744 \ud655\uc778\ud558\uc138\uc694.",
