    "foodPageDesc": "\u041f\u0443\u0442\u0435\u0448\u0435\u0441\u0442\u0432\u0438\u0435 \u043f\u043e \u0432\u043a\u0443\u0441\u0430\u043c \u041a\u0438\u0442\u0430\u044f. \u0418\u0441\u0441\u043b\u0435\u0434\u0443\u0439\u0442\u0435 \u0441\u044b\u0447\u0443\u0430\u043d\u044c\u0441\u043a\u0443\u044e, \u043a\u0430\u043d\u0442\u043e\u043d\u0441\u043a\u0443\u044e \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0440\u0435\u0433\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0435 \u043a\u0443\u0445\u043d\u0438.",
    "metaDescFood": "\u041e\u0442\u043a\u0440\u043e\u0439\u0442\u0435 \u0434\u043b\u044f \u0441\u0435\u0431\u044f \u0430\u0443\u0442\u0435\u043d\u0442\u0438\u0447\u043d\u0443\u044e \u043a\u0438\u0442\u0430\u0439\u0441\u043a\u0443\u044e \u043a\u0443\u0445\u043d\u044e \u2014 \u043e\u0442 \u043f\u0435\u043a\u0438\u043d\u0441\u043a\u043e\u0439 \u0443\u0442\u043a\u0438 \u0438 \u0434\u0438\u043c\u0441\u0430\u043c\u0430 \u0434\u043e \u0440\u0435\u0433\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0445 \u0434\u0435\u043b\u0438\u043a\u0430\u0442\u0435\u0441\u043e\u0432. \u0421\u043f\u043b\u0430\u043d\u0438\u0440\u0443\u0439\u0442\u0435 \u0441\u0432\u043e\u0451 \u043a\u0443\u043b\u0438\u043d\u0430\u0440\u043d\u043e\u0435 \u043f\u0443\u0442\u0435\u0448\u0435\u0441\u0442\u0432\u0438\u0435 \u043f\u043e \u041a\u0438\u0442\u0430\u044e.",
    "metaDescPekingDuck": "\u041f\u0435\u043a\u0438\u043d\u0441\u043a\u0430\u044f \u0443\u0442\u043a\u0430 \u2014 \u0445\u0440\u0443\u0441\u0442\u044f\u0449\u0430\u044f \u0436\u0430\u0440\u0435\u043d\u0430\u044f \u0443\u0442\u043a\u0430, \u043d\u0430\u0440\u0435\u0437\u0430\u0435\u043c\u0430\u044f \u0437\u0430 \u0441\u0442\u043e\u043b\u043e\u043c, \u043b\u0435\u0433\u0435\u043d\u0434\u0430\u0440\u043d\u043e\u0435 \u0438\u043c\u043f\u0435\u0440\u0430\u0442\u043e\u0440\u0441\u043a\u043e\u0435 \u0431\u043b\u044e\u0434\u043e \u0438\u0437 \u041f\u0435\u043a\u0438\u043d\u0430, \u043f\u043e\u0434\u0430\u0432\u0430\u0435\u043c\u043e\u0435 \u0441 \u0431\u043b\u0438\u043d\u0430\u043c\u0438, \u0437\u0435\u043b\u0435\u043d\u044b\u043c \u043b\u0443\u043a\u043e\u043c \u0438 \u0441\u043b\u0430\u0434\u043a\u0438\u043c \u0441\u043e\u0443\u0441\u043e\u043c.",
    "metaDescDimSum": "\u0414\u0438\u0301\u043c\u0441\u0430\u043c \u2014 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u043d\u044b\u0439 \u043a\u0430\u043d\u0442\u043e\u043d\u0441\u043a\u0438\u0439 \u0431\u0440\u0430\u043d\u0447 \u0438\u0437 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0445 \u0431\u043b\u044e\u0434, \u0432\u043a\u043b\u044e\u0447\u0430\u044f \u043a\u0440\u0435\u0432\u0435\u0442\u043e\u0447\u043d\u044b\u0435 \u043f\u0435\u043b\u044c\u043c\u0435\u043d\u0438, \u0448\u0430\u043e-\u043c\u0430\u0439 \u0438 \u0431\u0430\u0440\u0431\u0435\u043a\u044e-\u0431\u0430\u043e, \u043f\u043e\u0434\u0430\u0432\u0430\u0435\u043c\u044b\u0439 \u0441 \u0447\u0430\u0435\u043c \u0432 \u044d\u043b\u0435\u0433\u0430\u043d\u0442\u043d\u044b\u0445 \u043f\u0430\u0440\u043e\u0432\u044b\u0445 \u043a\u043e\u0440\u0437\u0438\u043d\u043a\u0430\u0445.",
    "metaDescHotpot": "\u0425\u043e\u0442-\u043f\u043e\u0442 \u2014 \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0439 \u0444\u043e\u0440\u043c\u0430\u0442 \u0442\u0440\u0430\u043f\u0435\u0437\u044b, \u043f\u0440\u0438 \u043a\u043e\u0442\u043e\u0440\u043e\u043c \u0433\u043e\u0441\u0442\u0438 \u0433\u043e\u0442\u043e\u0432\u044f\u0442 \u0442\u043e\u043d\u043a\u043e \u043d\u0430\u0440\u0435\u0437\u0430\u043d\u043d\u043e\u0435 \u043c\u044f\u0441\u043e, \u043e\u0432\u043e\u0449\u0438 \u0438 \u043b\u0430\u043f\u0448\u0443 \u0432 \u043a\u0438\u043f\u044f\u0449\u0435\u043c \u0431\u0443\u043b\u044c\u043e\u043d\u0435 \u0437\u0430 \u0441\u0442\u043e\u043b\u043e\u043c, \u043e\u0431\u043c\u0430\u043a\u0438\u0432\u0430\u044f \u043a\u0430\u0436\u0434\u044b\u0439 \u0438\u043d\u0433\u0440\u0435\u0434\u0438\u0435\u043d\u0442 \u0432 \u0430\u0440\u043e\u043c\u0430\u0442\u043d\u044b\u0435 \u0441\u043e\u0443\u0441\u044b.",
    "metaDescDumplings": "\u0426\u0437\u044f\u043e\u0446\u0437\u044b (\u043f\u0435\u043b\u044c\u043c\u0435\u043d\u0438) \u2014 \u0437\u0430\u0432\u043e\u0440\u043e\u0442\u044b \u0438\u0437 \u043c\u044f\u0441\u0430 \u0438 \u043e\u0432\u043e\u0449\u0435\u0439 \u0432 \u0442\u043e\u043d\u043a\u0438\u0445 \u0442\u0435\u0441\u0442\u044f\u043d\u044b\u0445 \u043e\u0431\u0451\u0440\u0442\u043a\u0430\u0445, \u0434\u043e\u0440\u043e\u0433\u0430\u044f \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u044f \u043a\u0438\u0442\u0430\u0439\u0441\u043a\u043e\u0433\u043e \u041d\u043e\u0432\u043e\u0433\u043e \u0433\u043e\u0434\u0430 \u0438 \u043a\u0440\u0443\u0433\u043b\u043e\u0433\u043e\u0434\u0438\u0447\u043d\u0430\u044f \u043a\u043e\u043c\u0444\u043e\u0440\u0442\u043d\u0430\u044f \u0435\u0434\u0430 \u043d\u0430 \u0441\u0435\u0432\u0435\u0440\u0435 \u041a\u0438\u0442\u0430\u044f.",
